# Make Iterator — process AI output item by item
# Use case: Ask GPT-4o to produce a JSON array, then iterate over it.

# Module 1 (Webhook): receives {"topic": "vector databases"}
# Module 2 (OpenAI): prompt asks for a JSON array of 5 subtopics
#   Output stored in: {{2.choices[].message.content}}
# Module 3 (JSON → Parse JSON): parses the JSON string into an array
# Module 4 (Iterator): iterates over {{3.array}}
#   Each iteration emits a single item: {{4.value}}
# Module 5 (Google Docs): creates one Doc per subtopic using {{4.value}}

# The iterator automatically handles any array length — no loop code needed.
# Add an Aggregator after the iterator to recombine results into a new array.

# Structured extraction pattern — make AI output reliable across runs

# Step 1: AI Step / OpenAI Module prompt
system_prompt = """
Extract the following fields from the customer email below.
Return ONLY a JSON object with no prose. Example:
{"intent": "refund", "order_id": "ORD-001", "urgency": "high"}
""".strip()

# Step 2 (Zapier): Use the Code action to validate
# Step 2 (Make):   Use the JSON → Parse JSON module

# In Zapier Code action (JavaScript):
code = '''
const text = inputData.ai_output;
let parsed;
try {
  // strip markdown code fences if model wraps JSON in ```
  const clean = text.replace(/^```json\n?|\n?```$/g, "").trim();
  parsed = JSON.parse(clean);
} catch (e) {
  // fall back to a safe default so the Zap doesn't break
  parsed = { intent: "unknown", order_id: "", urgency: "low" };
}
output = [{ parsed_intent: parsed.intent, parsed_order_id: parsed.order_id, parsed_urgency: parsed.urgency }];
'''

# RAG pattern in Make — retrieve context before calling the LLM
#
# Scenario: customer asks a product question via chat widget
#
# Module 1 (Webhook trigger):   {"user_id": "u-42", "question": "Does X support SSO?"}
# Module 2 (OpenAI Embeddings): embed {{1.question}} → {{2.data[].embedding}}
# Module 3 (HTTP GET Pinecone): query vector store for top-3 similar chunks
#   POST https://index.pinecone.io/query
#   Body: {"vector": {{2.data[].embedding}}, "topK": 3, "includeMetadata": true}
# Module 4 (OpenAI Completion):
#   System: "Answer using only the context below."
#   User:   "Context: {{3.matches[].metadata.text}}\nQuestion: {{1.question}}"
# Module 5 (Webhook Response): {"answer": {{4.choices[].message.content}}}
